#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e4+5;
int n,a[N],Ans,sum,m;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read();
    for(int i=1;i<=n;i++)
        a[i]=read(),sum+=a[i];
    for(int i=1;i<n;i++)
        Ans=max(Ans,a[i]+a[i+1]);
    Ans=max(Ans,a[n]+a[1]);
    m=n/2;
    Ans=max(Ans,(sum+m-1)/m);
    cout<<Ans<<"\n";
    return 0;
}
